import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
  Transformer,
  Label,
  Tag,
  Text,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
  // NEW: function to delete an annotation
  onDeleteAnnotation,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);

  // Master group offset (image panning)
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes (while drawing)
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // Points annotation
  const [tempPointPoints, setTempPointPoints] = useState([]);
  const [drawingPoint, setDrawingPoint] = useState(false);

  // For selecting shape to transform (only for bbox, ellipse)
  const [selectedAnnotationIndex, setSelectedAnnotationIndex] = useState(null);
  const transformerRef = useRef(null);

  // We'll store refs only for shapes that can be transformed: bbox, ellipse
  const shapeRefs = useRef([]);

  // Track last click time for double-click (finish polygon/polyline)
  const lastClickTimeRef = useRef(0);
  const doubleClickThreshold = 250; // ms

  // NEW: for copy/paste
  const [copiedAnnotation, setCopiedAnnotation] = useState(null);

  // ----------- Window / container sizing -----------
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ----------- Load image -----------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // ----------- Flatten points helper -----------
  function flattenPoints(pts) {
    return pts.flatMap((p) => [p.x, p.y]);
  }

  // ----------- Relative pointer position -----------
  function getGroupPos(evt) {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  }

  // ----------- Checking if shape is outside image -----------
  function shapeBoundingBox(ann) {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    // handle 'points' array
    else if (ann.type === 'points') {
      let minX = Infinity,
        minY = Infinity,
        maxX = -Infinity,
        maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    }
    return null;
  }

  function isOutsideImage(ann) {
    if (!konvaImg) return false;
    const box = shapeBoundingBox(ann);
    if (!box) return false;
    const { x1, y1, x2, y2 } = box;
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  }

  // ----------- Creating BBox -----------
  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Polygon -----------
  function addPolygonPoint(pos) {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Polyline -----------
  function addPolylinePoint(pos) {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Points (multiple point tool) -----------
  function addPointToPoints(pos) {
    setTempPointPoints((prev) => [...prev, pos]);
    setDrawingPoint(true);
  }
  function finalizePoint() {
    if (tempPointPoints.length > 0) {
      const newAnn = { type: 'points', points: tempPointPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPointPoints([]);
    setDrawingPoint(false);
    onFinishShape && onFinishShape();
  }

  // ----------- Creating Ellipse -----------
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  // ----------- Cancel shape on ESC -----------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
      setTempPointPoints([]);
      setDrawingPoint(false);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // ----------- Wheel Zoom -----------
  function handleWheel(evt) {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  }

  // ----------- Right-click remove last *drawing* point -----------
  // (But we'll also allow removing finished vertices individually below)
  function handleContextMenu(evt) {
    evt.evt.preventDefault();
    if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
      setTempPoints((prev) => prev.slice(0, -1));
    } else if (
      selectedTool === 'polyline' &&
      drawingPolyline &&
      tempPolyline.length > 0
    ) {
      setTempPolyline((prev) => prev.slice(0, -1));
    } else if (
      selectedTool === 'point' &&
      drawingPoint &&
      tempPointPoints.length > 0
    ) {
      setTempPointPoints((prev) => prev.slice(0, -1));
    }
  }

  // ----------- Mouse events for shape creation -----------
  function handleMouseDown(evt) {
    if (selectedTool === 'move') {
      return;
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    const now = Date.now();
    const delta = now - lastClickTimeRef.current;
    if (
      (selectedTool === 'polygon' ||
        selectedTool === 'polyline' ||
        selectedTool === 'point') &&
      delta < doubleClickThreshold
    ) {
      return; // double-click => handled in handleDblClick
    }
    lastClickTimeRef.current = now;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPointToPoints(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    }
  }

  function handleMouseMove(evt) {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  }

  function handleMouseUp() {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  }

  function handleDblClick() {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    } else if (selectedTool === 'point' && drawingPoint) {
      finalizePoint();
    }
  }

  // ----------- Copy/Paste Keyboard Listener -----------
  useEffect(() => {
    const handleKeyDown = (e) => {
      // Copy
      if (e.ctrlKey && (e.key === 'c' || e.key === 'C')) {
        if (selectedAnnotationIndex !== null) {
          e.preventDefault();
          setCopiedAnnotation(annotations[selectedAnnotationIndex]);
        }
      }
      // Paste
      if (e.ctrlKey && (e.key === 'v' || e.key === 'V')) {
        if (copiedAnnotation) {
          e.preventDefault();
          const newAnn = JSON.parse(JSON.stringify(copiedAnnotation));
          if (newAnn.x !== undefined && newAnn.y !== undefined) {
            newAnn.x += 10;
            newAnn.y += 10;
          } else if (newAnn.points) {
            newAnn.points = newAnn.points.map((pt) => ({
              x: pt.x + 10,
              y: pt.y + 10,
            }));
          }
          onAnnotationsChange([...annotations, newAnn]);
        }
      }

      // Remove last "drawing" point if user is in the middle of creating polygon, polyline, or points
      if (e.key === 'Backspace' || e.key === 'Delete') {
        if (selectedTool === 'polygon' && drawingPolygon && tempPoints.length > 0) {
          e.preventDefault();
          setTempPoints((prev) => prev.slice(0, -1));
        } else if (
          selectedTool === 'polyline' &&
          drawingPolyline &&
          tempPolyline.length > 0
        ) {
          e.preventDefault();
          setTempPolyline((prev) => prev.slice(0, -1));
        } else if (
          selectedTool === 'point' &&
          drawingPoint &&
          tempPointPoints.length > 0
        ) {
          e.preventDefault();
          setTempPointPoints((prev) => prev.slice(0, -1));
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [
    annotations,
    onAnnotationsChange,
    selectedAnnotationIndex,
    copiedAnnotation,
    selectedTool,
    drawingPolygon,
    drawingPolyline,
    drawingPoint,
    tempPoints,
    tempPolyline,
    tempPointPoints,
  ]);

  // ----------- Draggable logic for entire shapes -----------
  const handleBBoxDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handleEllipseDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handlePointDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const updated = [...annotations];
    updated[index] = { ...updated[index], x, y };
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handlePolylineDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const ann = annotations[index];
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    e.target.position({ x: 0, y: 0 });
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  const handlePolygonDragEnd = (index, e) => {
    const { x, y } = e.target.position();
    const ann = annotations[index];
    const newPoints = ann.points.map((pt) => ({
      x: pt.x + x,
      y: pt.y + y,
    }));
    const updated = [...annotations];
    updated[index] = { ...ann, points: newPoints };
    e.target.position({ x: 0, y: 0 });
    if (isOutsideImage(updated[index])) {
      updated.splice(index, 1);
    }
    onAnnotationsChange(updated);
  };

  // ----------- Remove an individual vertex from polygon, polyline, or points -----------
  function handleRemoveVertex(annIndex, vertexIndex) {
    const updated = [...annotations];
    const ann = { ...updated[annIndex] };
    const shapePoints = [...ann.points];
    shapePoints.splice(vertexIndex, 1);

    if (ann.type === 'polygon' && shapePoints.length < 3) {
      // removing any vertex if polygon has < 3 left => remove shape
      updated.splice(annIndex, 1);
    } else if (ann.type === 'polyline' && shapePoints.length < 2) {
      // removing any vertex if polyline has < 2 left => remove shape
      updated.splice(annIndex, 1);
    } else if (ann.type === 'points' && shapePoints.length < 1) {
      // removing any point if "points" shape has 0 => remove shape
      updated.splice(annIndex, 1);
    } else {
      ann.points = shapePoints;
      updated[annIndex] = ann;
    }

    onAnnotationsChange(updated);
  }

  // ----------- Draggable logic for each vertex -----------
  const handleVertexDragEnd = (annIndex, vertexIndex, e) => {
    e.cancelBubble = true;
    const { x, y } = e.target.position();
    const updated = [...annotations];
    const shapePoints = [...updated[annIndex].points];
    shapePoints[vertexIndex] = { x, y };
    updated[annIndex] = { ...updated[annIndex], points: shapePoints };
    if (isOutsideImage(updated[annIndex])) {
      updated.splice(annIndex, 1);
    }
    onAnnotationsChange(updated);
  };

  // ----------- Transformer logic -----------
  useEffect(() => {
    const tr = transformerRef.current;
    if (!tr) return;

    if (selectedAnnotationIndex == null) {
      tr.nodes([]);
      return;
    }
    const node = shapeRefs.current[selectedAnnotationIndex];
    if (node) {
      tr.nodes([node]);
      tr.getLayer().batchDraw();
    } else {
      tr.nodes([]);
    }
  }, [selectedAnnotationIndex, annotations, onAnnotationsChange]);

  const handleTransformEnd = () => {
    if (selectedAnnotationIndex == null) return;
    const shapeNode = shapeRefs.current[selectedAnnotationIndex];
    if (!shapeNode) return;

    const ann = annotations[selectedAnnotationIndex];
    const scaleX = shapeNode.scaleX();
    const scaleY = shapeNode.scaleY();
    const offsetX = shapeNode.x();
    const offsetY = shapeNode.y();

    let updatedAnn = { ...ann };

    switch (ann.type) {
      case 'bbox': {
        const newWidth = shapeNode.width() * scaleX;
        const newHeight = shapeNode.height() * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.width = newWidth;
        updatedAnn.height = newHeight;
        break;
      }
      case 'ellipse': {
        const newRadiusX = (shapeNode.width() / 2) * scaleX;
        const newRadiusY = (shapeNode.height() / 2) * scaleY;
        updatedAnn.x = offsetX;
        updatedAnn.y = offsetY;
        updatedAnn.radiusX = newRadiusX;
        updatedAnn.radiusY = newRadiusY;
        break;
      }
      default:
        break;
    }

    // reset scale
    shapeNode.scaleX(1);
    shapeNode.scaleY(1);
    shapeNode.x(0);
    shapeNode.y(0);

    const updatedAll = [...annotations];
    updatedAll[selectedAnnotationIndex] = updatedAnn;

    if (isOutsideImage(updatedAnn)) {
      updatedAll.splice(selectedAnnotationIndex, 1);
    }
    onAnnotationsChange(updatedAll);
  };

  // ----------- Helper to place "Delete" label -----------
  function getBoundingBox(ann) {
    const box = shapeBoundingBox(ann);
    if (!box) return null;
    return box;
  }

  // ----------- The main render -----------
  const fillColor = activeLabelColor + '55';

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
        onContextMenu={handleContextMenu}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {/* Background image */}
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Render existing annotations */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                return (
                  <React.Fragment key={i}>
                    <Rect
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      width={ann.width}
                      height={ann.height}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragStart={(e) => (e.cancelBubble = true)}
                      onDragMove={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handleBBoxDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <React.Fragment key={i}>
                    <Ellipse
                      ref={(node) => (shapeRefs.current[i] = node)}
                      x={ann.x}
                      y={ann.y}
                      radiusX={ann.radiusX}
                      radiusY={ann.radiusY}
                      rotation={ann.rotation || 0}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragStart={(e) => (e.cancelBubble = true)}
                      onDragMove={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handleEllipseDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'point') {
                return (
                  <React.Fragment key={i}>
                    <Circle
                      x={ann.x}
                      y={ann.y}
                      radius={6 / scale}
                      fill={activeLabelColor}
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePointDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    />
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'polyline') {
                const pts = flattenPoints(ann.points);
                const firstPt = ann.points[0];
                const secondPt =
                  ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolylineDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      <Line
                        points={pts}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        closed={false}
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={activeLabelColor}
                          strokeWidth={1 / scale}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          // Right-click (or context menu) to remove this vertex
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                        />
                      ))}
                      <Arrow
                        points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
                        fill={activeLabelColor}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'polygon') {
                const pts = flattenPoints(ann.points);
                const firstPt = ann.points[0];
                const secondPt =
                  ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolygonDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      <Line
                        points={pts}
                        fill={fillColor}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        closed
                      />
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={4 / scale}
                          fill="#fff"
                          stroke={activeLabelColor}
                          strokeWidth={1 / scale}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          // Right-click (or context menu) to remove this vertex
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                        />
                      ))}
                      <Arrow
                        points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
                        fill={activeLabelColor}
                        stroke={activeLabelColor}
                        strokeWidth={2 / scale}
                        pointerLength={10 / scale}
                        pointerWidth={8 / scale}
                      />
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              } else if (ann.type === 'points') {
                return (
                  <React.Fragment key={i}>
                    <Group
                      draggable
                      onMouseDown={(e) => (e.cancelBubble = true)}
                      onDragEnd={(e) => {
                        e.cancelBubble = true;
                        handlePolylineDragEnd(i, e);
                      }}
                      onClick={(e) => {
                        if (selectedTool === 'move') {
                          e.cancelBubble = true;
                          setSelectedAnnotationIndex(i);
                        }
                      }}
                    >
                      {ann.points.map((pt, idx) => (
                        <Circle
                          key={idx}
                          x={pt.x}
                          y={pt.y}
                          radius={6 / scale}
                          fill={activeLabelColor}
                          draggable
                          onMouseDown={(ev) => (ev.cancelBubble = true)}
                          onDragEnd={(ev) => handleVertexDragEnd(i, idx, ev)}
                          // Right-click (or context menu) to remove this point
                          onContextMenu={(ev) => {
                            ev.evt.preventDefault();
                            ev.cancelBubble = true;
                            handleRemoveVertex(i, idx);
                          }}
                        />
                      ))}
                    </Group>
                    {selectedAnnotationIndex === i && (
                      <DeleteLabel
                        annotation={ann}
                        scale={scale}
                        shapeBoundingBox={shapeBoundingBox}
                        onDelete={() => onDeleteAnnotation(i)}
                      />
                    )}
                  </React.Fragment>
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && selectedTool === 'polygon' && (
              <>
                {tempPoints.length > 1 && (
                  <Line
                    points={flattenPoints([...tempPoints, tempPoints[0]])}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed
                  />
                )}
                {tempPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && selectedTool === 'polyline' && (
              <>
                {tempPolyline.length > 1 && (
                  <Line
                    points={flattenPoints(tempPolyline)}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    closed={false}
                  />
                )}
                {tempPolyline.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={newEllipse.rotation}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Points */}
            {drawingPoint && selectedTool === 'point' && (
              <>
                {tempPointPoints.map((pt, idx) => (
                  <Circle
                    key={idx}
                    x={pt.x}
                    y={pt.y}
                    radius={4 / scale}
                    fill="#fff"
                    stroke={activeLabelColor}
                    strokeWidth={1 / scale}
                  />
                ))}
              </>
            )}
          </Group>

          {/* Transformer (only for bbox & ellipse) */}
          <Transformer
            ref={transformerRef}
            rotateEnabled={false}
            anchorSize={8}
            borderDash={[6, 2]}
            onTransformEnd={handleTransformEnd}
            onDragEnd={handleTransformEnd}
          />
        </Layer>
      </Stage>
    </div>
  );
}

// A small Konva Label to let user delete a selected annotation
function DeleteLabel({ annotation, scale, shapeBoundingBox, onDelete }) {
  const box = shapeBoundingBox(annotation);
  if (!box) return null;

  // We'll place the label slightly above top-left corner
  const xPos = box.x1;
  const yPos = box.y1 - 20 / scale; // 20 px above, scaled

  return (
    <Label
      x={xPos}
      y={yPos}
      onClick={(e) => {
        e.cancelBubble = true;
        onDelete();
      }}
      scaleX={1 / scale}
      scaleY={1 / scale}
    >
      <Tag fill="red" opacity={0.8} cornerRadius={4} />
      <Text text="Delete" fill="#fff" padding={5} fontSize={14} />
    </Label>
  );
}
